/* ── Helper: create a dummy adamw_opt for scheduler tests ── */

static adamw_opt *make_test_opt(float base_lr) {
    /* Create a minimal 1-param model just to have a valid adamw_opt */
    tensor *p = tensor_zeros(1, (int[]){1}, 1);  /* one param with grad */
    tensor **params = mem_params_alloc(sizeof(tensor*), NULL);
    params[0] = p;

    adamw_opt *opt = adamw_create(params, 1, base_lr, 0.9f, 0.999f, 1e-8f, 0.01f);
    return opt;
}

/* ── Test: schedule sequences match PyTorch reference ── */

static void test_schedule_sequence(const char *name, int schedule,
                                    float base_lr, int warmup, int total,
                                    float min_lr, int step_sz, float gamma,
                                    const float *ref, int n_steps) {
    printf("  test_%s_sequence... ", name);

    /* Compact pools just for this test */
    mem_pool params_small  = mem_pool_create(256 * 1024);
    mem_pool scratch_small = mem_pool_create(256 * 1024);
    mem_pool data_small    = mem_pool_create(256 * 1024);
    mem_pool_set_defaults(&params_small, &scratch_small, &data_small);

    adamw_opt *opt = make_test_opt(base_lr);

    lr_scheduler *sched = lr_scheduler_create(opt, schedule,
                                               base_lr, warmup, total,
                                               min_lr, step_sz, gamma);

    /* Step 0 (after create) should match ref[0] */
    float lr0 = lr_scheduler_get_lr(sched);
    if (fabsf(lr0 - ref[0]) > EPS) {
        printf("FAIL: step 0: got %.10f, expected %.10f\n", lr0, ref[0]);
        assert(0);
    }

    /* Manually set opt->lr to avoid resetting repeatedly */
    for (int t = 1; t < n_steps; t++) {
        lr_scheduler_step(sched);
        float lr = lr_scheduler_get_lr(sched);
        if (fabsf(lr - ref[t]) > EPS) {
            printf("FAIL: step %d: got %.10f, expected %.10f\n", t, lr, ref[t]);
            assert(0);
        }
        /* Also verify opt->lr matches */
        if (fabsf(opt->lr - ref[t]) > EPS) {
            printf("FAIL: opt->lr at step %d: got %.10f, expected %.10f\n",
                   t, opt->lr, ref[t]);
            assert(0);
        }
    }

    mem_pool_destroy(&params_small);
    mem_pool_destroy(&scratch_small);
    mem_pool_destroy(&data_small);
    printf("OK\n");
}

/* ── Test: create with default min_lr ── */

static void test_default_min_lr(void) {
    printf("  test_default_min_lr... ");

    mem_pool params_small  = mem_pool_create(256 * 1024);
    mem_pool scratch_small = mem_pool_create(256 * 1024);
    mem_pool data_small    = mem_pool_create(256 * 1024);
    mem_pool_set_defaults(&params_small, &scratch_small, &data_small);

    adamw_opt *opt = make_test_opt(0.01f);

    /* min_lr < 0 → should default to base_lr/10 */
    lr_scheduler *sched = lr_scheduler_create(opt, LR_SCHEDULE_COSINE,
                                               0.01f, 0, 100, -1.0f, 0, 0);
    assert(fabsf(sched->min_lr - 0.001f) < EPS);
    printf("OK (min_lr=%f)\n", sched->min_lr);

    mem_pool_destroy(&params_small);
    mem_pool_destroy(&scratch_small);
    mem_pool_destroy(&data_small);
}

/* ── Test: reset ── */

static void test_reset(void) {
    printf("  test_reset... ");

    mem_pool params_small  = mem_pool_create(256 * 1024);
    mem_pool scratch_small = mem_pool_create(256 * 1024);
    mem_pool data_small    = mem_pool_create(256 * 1024);
    mem_pool_set_defaults(&params_small, &scratch_small, &data_small);

    adamw_opt *opt = make_test_opt(0.001f);

    lr_scheduler *sched = lr_scheduler_create(opt, LR_SCHEDULE_LINEAR_WARMUP_COSINE,
                                               0.001f, 10, 100, 1e-5f, 0, 0);

    /* Advance some steps */
    for (int i = 0; i < 20; i++)
        lr_scheduler_step(sched);

    float mid_lr = lr_scheduler_get_lr(sched);
    assert(fabsf(mid_lr - 9.701478472890247e-04f) < EPS &&
           "mid-step LR should be near warmup end");

    /* Reset → back to step 0 */
    lr_scheduler_reset(sched);
    float reset_lr = lr_scheduler_get_lr(sched);
    assert(fabsf(reset_lr - 1.000000000000000e-04f) < EPS &&
           "reset LR should equal warmup step 0");

    /* Stepping again from 0 should follow same trajectory */
    lr_scheduler_step(sched);
    float after_reset = lr_scheduler_get_lr(sched);
    assert(fabsf(after_reset - 2.000000000000000e-04f) < EPS &&
           "after-reset step 1 should match warmup step 1");

    printf("OK\n");

    mem_pool_destroy(&params_small);
    mem_pool_destroy(&scratch_small);
    mem_pool_destroy(&data_small);
}

