/* ── Test: scheduler with actual model training ── */

static void test_scheduler_with_training(void) {
    printf("  test_scheduler_with_training... ");

    mem_pool params  = mem_pool_create(2 * 1024 * 1024);
    mem_pool scratch = mem_pool_create(2 * 1024 * 1024);
    mem_pool data    = mem_pool_create(2 * 1024 * 1024);
    mem_pool_set_defaults(&params, &scratch, &data);

    /* Create minimal decoder LM */
    decoder_lm *lm = decoder_lm_create(8, 8, 2, 2, 4, 16);

    /* Collect params */
    tensor *all_params[256];
    int n_params = 0;
    all_params[n_params++] = lm->embedding_table;
    all_params[n_params++] = lm->norm_weight;
    all_params[n_params++] = lm->norm_bias;
    all_params[n_params++] = lm->lm_head->weight;
    all_params[n_params++] = lm->lm_head->bias;
    for (int i = 0; i < lm->n_layers; i++) {
        transformer_block *b = lm->blocks[i];
        all_params[n_params++] = b->q_proj->weight;
        all_params[n_params++] = b->q_proj->bias;
        all_params[n_params++] = b->k_proj->weight;
        all_params[n_params++] = b->k_proj->bias;
        all_params[n_params++] = b->v_proj->weight;
        all_params[n_params++] = b->v_proj->bias;
        all_params[n_params++] = b->out_proj->weight;
        all_params[n_params++] = b->out_proj->bias;
        all_params[n_params++] = b->attn_norm_weight;
        all_params[n_params++] = b->attn_norm_bias;
        all_params[n_params++] = b->ffn_norm_weight;
        all_params[n_params++] = b->ffn_norm_bias;
        all_params[n_params++] = b->ffn->gate_proj->weight;
        all_params[n_params++] = b->ffn->gate_proj->bias;
        all_params[n_params++] = b->ffn->up_proj->weight;
        all_params[n_params++] = b->ffn->up_proj->bias;
        all_params[n_params++] = b->ffn->down_proj->weight;
        all_params[n_params++] = b->ffn->down_proj->bias;
    }

    adamw_opt *opt = adamw_create(all_params, n_params, 0.01f,
                                   0.9f, 0.999f, 1e-8f, 0.01f);

    /* Create scheduler with linear warmup + cosine */
    lr_scheduler *sched = lr_scheduler_create(opt, LR_SCHEDULE_LINEAR_WARMUP_COSINE,
                                                0.01f, 5, 20, 1e-4f, 0, 0);

    /* Train a few steps and verify LR follows schedule */
    float lrs[10];
    for (int step = 0; step < 10; step++) {
        lrs[step] = lr_scheduler_get_lr(sched);

        /* Create input_ids (B=2, N=4) */
        tensor *input_ids = tensor_zeros_data(2, (int[]){2, 4});
        int *id_data = (int *)input_ids->data;
        id_data[0] = 0; id_data[1] = 1; id_data[2] = 2; id_data[3] = 3;
        id_data[4] = 3; id_data[5] = 2; id_data[6] = 1; id_data[7] = 0;

        tensor *loss = decoder_lm_train_step(lm, input_ids, opt, 0.0f, NULL);
        (void)loss;

        lr_scheduler_step(sched);

        mem_pool_reset(&scratch);
        mem_pool_reset(&data);
    }

    /* Verify LR progression: warmup steps 0-4 should increase, later decay */
    assert(lrs[0] < lrs[1] && "warmup: lr should increase");
    assert(lrs[1] < lrs[2] && "warmup: lr should increase");
    assert(lrs[4] < lrs[5] || fabsf(lrs[4] - lrs[5]) < EPS*10 &&
           "post-warmup: lr should start decaying");
    assert(fabsf(lrs[0] - 0.002f) < EPS &&
           "warmup step 0: lr = base_lr * 1/5 = 0.002");

    printf("OK (lrs: %.6f %.6f %.6f %.6f ... %.6f)\n",
           lrs[0], lrs[1], lrs[2], lrs[3], lrs[9]);

    mem_pool_destroy(&params);
    mem_pool_destroy(&scratch);
    mem_pool_destroy(&data);
}

int main(void) {
    printf("test_lr_scheduler:\n");

    /* Each test creates its own pools */
    test_default_min_lr();

    /* Sequential LR test against reference arrays */
    test_schedule_sequence("constant", LR_SCHEDULE_CONSTANT,
                            0.001f, 0, 0, 0, 0, 0,
                            lr_constant, 130);
    test_schedule_sequence("linear_warmup_cosine", LR_SCHEDULE_LINEAR_WARMUP_COSINE,
                            0.001f, 10, 100, 1e-5f, 0, 0,
                            lr_linear_warmup_cosine, 130);
    test_schedule_sequence("linear_warmup", LR_SCHEDULE_LINEAR_WARMUP,
                            0.001f, 10, 0, 0, 0, 0,
                            lr_linear_warmup, 130);
    test_schedule_sequence("cosine", LR_SCHEDULE_COSINE,
                            0.001f, 0, 100, 1e-5f, 0, 0,
                            lr_cosine, 130);
    test_schedule_sequence("step", LR_SCHEDULE_STEP,
                            0.001f, 0, 0, 0, 20, 0.5f,
                            lr_step, 130);
    test_schedule_sequence("exponential", LR_SCHEDULE_EXPONENTIAL,
                            0.001f, 0, 0, 0, 0, 0.5f,
                            lr_exponential, 130);

    test_get_lr_no_side_effects();
    test_reset();
    test_step_boundaries();
    test_exponential_values();
    test_constant_no_warmup();
    test_scheduler_with_training();

    printf("  ALL PASS\n");
    return 0;
}
